<template>
  <h3 class="title">Add Workout</h3>
  <div class="date-picker">
    <Datepicker v-model="date"></Datepicker>
  </div>
  <form class="form-container" @submit.prevent="addWorkout">
    <input
      class="form-input"
      type="text"
      placeholder="Workout name.."
      required
      v-model="workoutName"
    />
    <input
      class="form-input"
      type="text"
      placeholder="Workout reps.."
      required
      v-model="workoutReps"
    />
    <input
      class="form-input"
      type="text"
      placeholder="Workout sets.."
      required
      v-model="workoutSets"
    />
    <button>Add</button>
  </form>
  <SavedWorkouts @deleteWorkout="deleteWorkout" :workouts="workouts" />
</template>

<script>
import { ref } from "@vue/reactivity";
import SavedWorkouts from "./SavedWorkouts.vue";
import Datepicker from "@vuepic/vue-datepicker";
import "@vuepic/vue-datepicker/dist/main.css";
import moment from "moment";

export default {
  components: { SavedWorkouts, Datepicker },
  emits: ["deleteWorkout"],
  setup() {
    const workoutName = ref("");
    const workoutReps = ref("");
    const workoutSets = ref("");

    const date = ref();
    const formattedDate = moment(date).format("YYYY-MM-D");

    let workout = ref({});
    const defaultData = ref([]);
    const workoutsData =
      JSON.parse(localStorage.getItem("workouts")) || defaultData;
    const workouts = ref(workoutsData);

    const saveData = () => {
      const storageData = JSON.stringify(workouts.value);
      localStorage.setItem("workouts", storageData);
    };

    const addWorkout = () => {
      workout = {
        date: formattedDate,
        name: workoutName.value,
        reps: workoutReps.value,
        sets: workoutSets.value,
      };
      saveWorkout();
      workoutName.value = "";
      workoutReps.value = "";
      workoutSets.value = "";
    };

    const saveWorkout = () => {
      workouts.value.push(workout);
      saveData();
    };

    const deleteWorkout = (index) => {
      workouts.value.splice(index, 1);
      saveData();
    };

    return {
      workoutName,
      workoutReps,
      workoutSets,
      saveWorkout,
      deleteWorkout,
      workouts,
      addWorkout,
      date,
    };
  },
};
</script>

<style scoped>
.title {
  margin-top: 30px;
  font-size: 24px;
}
.date-picker {
  display: flex;
  justify-content: center;
}
.form-container {
  margin: 10px auto;
  max-width: 200px;
}
.form-container button {
  width: 70px;
  height: 35px;
  background-color: beige;
  border-radius: 10px;
  border: none;
  cursor: pointer;
  margin-top: 25px;
}
.form-input {
  width: 150px;
  height: 30px;
  font-size: 18px;
  text-align: center;
  margin-top: 25px;
  border: none;
  border-bottom: 1px solid black;
}
</style>
