<template>
  <h3 class="title">Saved Workouts:</h3>
  <h5 class="empty-workouts" v-if="workouts.length === 0">No workouts added</h5>
  <div class="saved-workouts">
    <div v-if="workouts.length > 0">
      <h3
        class="date"
        @click="showSavedWorkouts"
        v-for="(workout, index) in workouts"
        :key="index"
      >
        {{ workout.date }}
      </h3>
      <p v-if="!showWorkouts">Click date to show workouts</p>
    </div>
    <div
      class="show-workouts"
      v-for="(workout, index) in workouts"
      :key="index"
    >
      <p v-if="showWorkouts">
        Workout: {{ workout.name }} - Reps: {{ workout.reps }} - Sets:
        {{ workout.sets }}
        <button @click="$emit('deleteWorkout', index)">X</button>
      </p>
    </div>
  </div>
</template>

<script>
import { ref } from "@vue/reactivity";
export default {
  props: { workouts: Array },
  emits: ["deleteWorkout"],
  setup(props) {
    const showWorkouts = ref(false);
    const showSavedWorkouts = () => {
      showWorkouts.value = !showWorkouts.value;
    };

    const getCurrentDate = () => {
      const d = new Date();
      const day = d.getDate();
      const month = d.getMonth() + 1;
      const year = d.getFullYear();
      const currentDate = year + "-" + month + "-" + day;
      return currentDate;
    };

    return { getCurrentDate, showSavedWorkouts, showWorkouts };
  },
};
</script>

<style scoped>
.saved-workouts {
  max-width: 500px;
  margin: 10px auto;
}
.date {
  background-color: black;
  display: flex;
  justify-content: center;
  align-items: center;
  color: beige;
  width: 25%;
  margin-left: 38%;
  border-radius: 10px;
  cursor: pointer;
}
.show-workouts {
  display: flex;
  justify-content: space-around;
  align-items: center;
  width: 400px;
  margin: 0 auto;
}
.show-workouts p {
  display: flex;
  justify-content: space-between;
  width: 100%;
  font-size: 18px;
  margin-top: -10px;
  background-color: beige;
}
.show-workouts button {
  display: flex;
  justify-content: right;
  align-items: center;
  background-color: black;
  border-radius: 5px;
  color: beige;
  cursor: pointer;
}
</style>
